const orderData = $('Extract WhatsApp Data').first().json.order_data;
let parsed = {};
try {
  parsed = typeof orderData === 'string' ? JSON.parse(orderData) : (orderData || {});
} catch(e) { parsed = {}; }

const items = parsed.product_items || [];

// Mapa de tamanhos
const sizeMap = {
  'p': { code: 'p', name: 'Pequena', base_price: 35 },
  'm': { code: 'm', name: 'Média', base_price: 45 },
  'g': { code: 'g', name: 'Grande', base_price: 59 },
  'f': { code: 'f', name: 'Família', base_price: 75 }
};

// Expandir cada item por quantity
const pizzas = [];
let pizzaIndex = 0;
for (const it of items) {
  const retailerId = String(it.product_retailer_id || '').toLowerCase();
  const qty = Number(it.quantity) || 1;
  const itemPrice = Number(it.item_price) || 0;

  // Parse: pz_{size}_{N}s
  const m = retailerId.match(/^pz_([pmgf])_([12])s$/);
  if (!m) continue;
  const sizeCode = m[1];
  const qtdSabores = Number(m[2]);
  const sizeInfo = sizeMap[sizeCode];
  if (!sizeInfo) continue;

  // Cria 1 pizza para cada unidade (qty)
  for (let i = 0; i < qty; i++) {
    pizzas.push({
      index: pizzaIndex++,
      size_code: sizeCode,
      size_name: sizeInfo.name,
      qtd_sabores: qtdSabores,
      base_price: itemPrice > 0 ? itemPrice : sizeInfo.base_price,
      border: null,
      flavors: [],
      observation: '',
      total: 0,
      status: 'pending'
    });
  }
}

if (pizzas.length === 0) {
  return [{ json: { _error: 'no_pizzas', message: 'Não consegui identificar pizzas no pedido' } }];
}

// Inicializar contexto
const ctx = {
  pizzas,
  current_pizza_index: 0,
  current_step: 'border',
  delivery_fee: 8,
  previous_state: 'pz_catalog_pending'
};

return [{ json: { contexto: ctx } }];

const borders = $('Get Borders').first().json.borders || [];
const ctx = $('Parse Pizza Order').first().json.contexto;
const pizza = ctx.pizzas[ctx.current_pizza_index];
const total = ctx.pizzas.length;
const pos = ctx.current_pizza_index + 1;

const fmt = (v) => Number(v).toFixed(2).replace('.', ',');

const rows = borders.slice(0, 10).map(b => {
  const priceLabel = b.price > 0 ? `+R$ ${fmt(b.price)}` : 'Sem custo';
  return {
    id: `border_${b.id}`,
    title: b.name.slice(0, 24),
    description: priceLabel
  };
});

const body = {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: $('Extract WhatsApp Data').first().json.msg_to,
  type: "interactive",
  interactive: {
    type: "list",
    header: { type: "text", text: `🍕 Pizza ${pos}/${total} — ${pizza.size_name}` },
    body: { text: "Escolha o tipo de borda:" },
    footer: { text: "Selecione uma opção" },
    action: {
      button: "Ver bordas",
      sections: [{ title: "Bordas disponíveis", rows }]
    }
  }
};

return [{ json: { whatsapp_body: body } }];

const listId = $('Extract WhatsApp Data').first().json.list_id || '';
const m = listId.match(/^border_(.+)$/);

if (!m) {
  return [{ json: { _invalid: true, reason: 'no_list_id' } }];
}

const borderId = m[1];

// Pegar contexto atual
const norm = $('Normalize State1').first().json;
const ctx = norm.contexto || {};

if (!ctx.pizzas || ctx.pizzas.length === 0) {
  return [{ json: { _invalid: true, reason: 'no_pizzas' } }];
}

const pizza = ctx.pizzas[ctx.current_pizza_index];
if (!pizza) {
  return [{ json: { _invalid: true, reason: 'no_pizza' } }];
}

// Buscar dados da borda no resultado do Get Borders Re
// Por hora vamos guardar o id + nome (do Get Borders Re) e preço
return [{
  json: {
    border_id: borderId,
    contexto: ctx
  }
}];

const ctx = $('Handle Border Choice').first().json.contexto;
const borderId = $('Handle Border Choice').first().json.border_id;
const borders = $('Get Borders (Re)').first().json.borders || [];
const chosen = borders.find(b => String(b.id) === String(borderId)) || { id: borderId, name: 'N/A', price: 0 };

const i = ctx.current_pizza_index;
ctx.pizzas[i].border = {
  id: chosen.id,
  name: chosen.name,
  price: chosen.price
};

return [{ json: { contexto: ctx } }];

const flavors = $('Get Flavors (1)').first().json.flavors || [];
const ctx = $('Save Border to Ctx').first().json.contexto;
const pizza = ctx.pizzas[ctx.current_pizza_index];
const total = ctx.pizzas.length;
const pos = ctx.current_pizza_index + 1;

const fmt = (v) => Number(v).toFixed(2).replace('.', ',');

const rows = flavors.slice(0, 10).map(f => ({
  id: `flv1_${f.id}`,
  title: f.name.slice(0, 24),
  description: `+R$ ${fmt(f.adicional)}`
}));

const bodyText = pizza.qtd_sabores === 2
  ? `Escolha o *1º sabor* (da 1ª metade):`
  : `Escolha o sabor:`;

const body = {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: $('Extract WhatsApp Data').first().json.msg_to,
  type: "interactive",
  interactive: {
    type: "list",
    header: { type: "text", text: `🍕 Pizza ${pos}/${total} — ${pizza.size_name}` },
    body: { text: bodyText },
    footer: { text: "Selecione um sabor" },
    action: {
      button: "Ver sabores",
      sections: [{ title: "Sabores", rows }]
    }
  }
};

return [{ json: { whatsapp_body: body } }];

const listId = $('Extract WhatsApp Data').first().json.list_id || '';
const m = listId.match(/^flv1_(.+)$/);
if (!m) return [{ json: { _invalid: true } }];

const flavorId = m[1];
const norm = $('Normalize State1').first().json;
const ctx = norm.contexto || {};

return [{ json: { flavor_id: flavorId, contexto: ctx } }];

const ctx = $('Handle Flavor 1 Choice').first().json.contexto;
const flvId = $('Handle Flavor 1 Choice').first().json.flavor_id;
const flavors = $('Get Flavors (Re 1)').first().json.flavors || [];
const chosen = flavors.find(f => String(f.id) === String(flvId)) || { id: flvId, name: 'N/A', adicional: 0 };

const i = ctx.current_pizza_index;
ctx.pizzas[i].flavors = [{ id: chosen.id, name: chosen.name, adicional: chosen.adicional }];

return [{ json: { contexto: ctx, qtd_sabores: ctx.pizzas[i].qtd_sabores } }];

const flavors = $('Get Flavors (2)').first().json.flavors || [];
const ctx = $('Save Flavor 1 to Ctx').first().json.contexto;
const pizza = ctx.pizzas[ctx.current_pizza_index];
const total = ctx.pizzas.length;
