const fmt = (v) => Number(v).toFixed(2).replace('.', ',');

const rows = flavors.slice(0, 10).map(f => ({
  id: `flv2_${f.id}`,
  title: f.name.slice(0, 24),
  description: `+R$ ${fmt(f.adicional)}`
}));

const body = {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: $('Extract WhatsApp Data').first().json.msg_to,
  type: "interactive",
  interactive: {
    type: "list",
    header: { type: "text", text: `🍕 Pizza ${pos}/${total} — ${pizza.size_name}` },
    body: { text: `1º sabor: *${sabor1.name}*\n\nAgora escolha o *2º sabor* (2ª metade):` },
    footer: { text: "Selecione um sabor" },
    action: {
      button: "Ver sabores",
      sections: [{ title: "Sabores", rows }]
    }
  }
};

return [{ json: { whatsapp_body: body } }];

const listId = $('Extract WhatsApp Data').first().json.list_id || '';
const m = listId.match(/^flv2_(.+)$/);
if (!m) return [{ json: { _invalid: true } }];
const flavorId = m[1];
const norm = $('Normalize State1').first().json;
const ctx = norm.contexto || {};
return [{ json: { flavor_id: flavorId, contexto: ctx } }];

const ctx = $('Handle Flavor 2 Choice').first().json.contexto;
const flvId = $('Handle Flavor 2 Choice').first().json.flavor_id;
const flavors = $('Get Flavors (Re 2)').first().json.flavors || [];
const chosen = flavors.find(f => String(f.id) === String(flvId)) || { id: flvId, name: 'N/A', adicional: 0 };

const i = ctx.current_pizza_index;
const existing = ctx.pizzas[i].flavors || [];
ctx.pizzas[i].flavors = [...existing.slice(0, 1), { id: chosen.id, name: chosen.name, adicional: chosen.adicional }];

return [{ json: { contexto: ctx } }];

// Determinar qual contexto usar (vem de Save Flavor 1 OR Save Flavor 2)
let ctx = null;
try { ctx = $('Save Flavor 2 to Ctx').first().json.contexto; } catch(e) {}
if (!ctx) {
  try { ctx = $('Save Flavor 1 to Ctx').first().json.contexto; } catch(e) {}
}
if (!ctx) return [{ json: { _error: 'no_ctx' } }];

const i = ctx.current_pizza_index;
const p = ctx.pizzas[i];

// Total = base + soma dos adicionais dos sabores + preço da borda
let total = Number(p.base_price) || 0;
for (const f of (p.flavors || [])) {
  total += Number(f.adicional) || 0;
}
if (p.border && p.border.price) {
  total += Number(p.border.price) || 0;
}

p.total = total;
p.status = 'done';

return [{ json: { contexto: ctx } }];

const ctx = $('Compute Pizza Done').first().json.contexto;
const i = ctx.current_pizza_index;
const p = ctx.pizzas[i];
const total = ctx.pizzas.length;
const pos = i + 1;

const fmt = (v) => Number(v).toFixed(2).replace('.', ',');

const saboresTxt = (p.flavors || []).map(f => `${f.name} (+R$ ${fmt(f.adicional)})`).join(' + ');
const bordaTxt = p.border && p.border.price > 0
  ? `${p.border.name} (+R$ ${fmt(p.border.price)})`
  : (p.border ? p.border.name : '—');
const obsTxt = p.observation ? `\n📝 Obs: ${p.observation}` : '';

const isLast = (i + 1) >= total;
const nextLabel = isLast ? '✅ Finalizar' : '➡️ Próxima pizza';

