    type: "button",
    body: { text },
    action: {
      buttons: [
        { type: "reply", reply: { id: "pz_done_alter", title: "✏️ Alterar" } },
        { type: "reply", reply: { id: "pz_done_obs", title: "📝 Observação" } },
        { type: "reply", reply: { id: "pz_done_next", title: nextLabel.slice(0, 20) } }
      ]
    }
  }
};

return [{ json: { whatsapp_body: body } }];

const ctx = $('Normalize State1').first().json.contexto || {};
const p = ctx.pizzas[ctx.current_pizza_index];

const rows = [
  { id: "alter_border", title: "🥖 Trocar borda", description: "Selecionar outra borda" },
  { id: "alter_flv1", title: "🧀 Trocar 1º sabor", description: p.flavors[0] ? p.flavors[0].name : 'Não escolhido' }
