}

rows.push({ id: "alter_back", title: "↩️ Voltar", description: "Manter como está" });

const body = {
  messaging_product: "whatsapp",
  recipient_type: "individual",
  to: $('Extract WhatsApp Data').first().json.msg_to,
  type: "interactive",
