// Filtra pedidos ativos (não delivered/canceled)
const ACTIVE = ['pending_payment', 'preparing', 'ready_for_pickup', 'on_delivery'];
// Aceita também 'Order Placed' (legado) para compatibilidade
const LEGACY_ACTIVE = ['Order Placed'];

const allRows = $input.all().map(i => i.json).filter(r => r['Order ID']);
const rows = allRows.filter(r => {
  const s = r['Status'] || '';
  return ACTIVE.includes(s) || LEGACY_ACTIVE.includes(s);
});

const hasPending = rows.length > 0;
if (!hasPending) {
  return [{ json: { has_pending: false } }];
}

// Agrupa por Order ID
const grouped = {};
for (const r of rows) {
  const id = r['Order ID'];
  if (!grouped[id]) {
    grouped[id] = {
      id, date: r['Date'], status: r['Status'], items: [],
      address: r['Address'] || '', total: 0
    };
  }
  const qty = Number(r['Quantity']) || 0;
  const price = Number(r['Price']) || 0;
  grouped[id].items.push({
    text: `${qty}x ${r['Item']}`,
    line_total: qty * price
  });
  grouped[id].total += qty * price;
}

const orders = Object.values(grouped).sort((a, b) => String(b.date).localeCompare(String(a.date)));
const latest = orders[0];

// Mapear status para texto amigável
const statusLabel = {
  'pending_payment': '⏳ Aguardando confirmação',
  'preparing': '👨‍🍳 Em preparo',
  'ready_for_pickup': '📦 Pronto para retirada',
  'on_delivery': '🛵 Saiu para entrega',
  'Order Placed': '⏳ Aguardando confirmação'
};

const itemsPreview = latest.items.slice(0, 3).map(i => i.text).join(', ') + 
  (latest.items.length > 3 ? '...' : '');

return [{ json: {
  has_pending: true,
  pending_preview: itemsPreview,
  pending_count: orders.length,
  order_id: latest.id,
  status_label: statusLabel[latest.status] || latest.status
}}];

