const value = $('Whatsapp Bot Webhook1').first().json.body.entry[0].changes[0].value;

const message = value.messages?.[0] || {};
const contact = value.contacts?.[0] || {};
const metadata = value.metadata || {};

const msgType = message.type || '';

let msgText = '';
let buttonId = '';
let listId = '';
let orderData = '';
let interactiveType = '';

if (msgType === 'text') {
  msgText = message.text?.body || '';
}

if (msgType === 'interactive') {
  const interactive = message.interactive || {};
  interactiveType = interactive.type || '';

  if (interactive.type === 'button_reply') {
    buttonId = interactive.button_reply?.id || '';
  }

  if (interactive.type === 'list_reply') {
    listId = interactive.list_reply?.id || '';
  }
}

if (msgType === 'order') {
  orderData = JSON.stringify(message.order || {});
}

return [
  {
    json: {
      tenant_id: $('Set Variable1').first().json.tenant_id || 'pizza_a',
      msg_to: contact.wa_id || message.from || '',
      msg_from_business: metadata.display_phone_number || '',
      phone_number_id: metadata.phone_number_id || '',
      msg_type: msgType,
      interactive_type: interactiveType,
      msg_text: msgText,
      button_id: buttonId,
      list_id: listId,
      order_data: orderData,
      user_name: contact.profile?.name || ''
    }
  }
];
